Here is a complete implementation of a thread-safe object pool combining RCU and atomic reference counting.

```c
#include <linux/slab.h>
#include <linux/rcupdate.h>
#include <linux/refcount.h>

struct pool_entry {
    int id;
    refcount_t refs;
    struct rcu_head rcu;
    struct hlist_node node;
    void *data;
};

struct object_pool {
    struct hlist_head buckets[64];
    spinlock_t bucket_locks[64];
};

static struct object_pool pool;

static void pool_entry_free(struct rcu_head *rcu) {
    struct pool_entry *e = container_of(rcu, struct pool_entry, rcu);
    kfree(e->data);
    kfree(e);
}

/* Lookup with RCU + refcount */
struct pool_entry *pool_get(int id) {
    struct pool_entry *e;
    unsigned int hash = hash_32(id, 6);
    rcu_read_lock();
    hlist_for_each_entry_rcu(e, &pool.buckets[hash], node) {
        if (e->id == id) {
            if (refcount_inc_not_zero(&e->refs)) {
                rcu_read_unlock();
                return e;  /* Caller must call pool_put */
            }
            break;  /* Being freed — not found */
        }
    }
    rcu_read_unlock();
    return NULL;
}

void pool_put(struct pool_entry *e) {
    if (refcount_dec_and_test(&e->refs))
        call_rcu(&e->rcu, pool_entry_free);
}

/* Insert */
int pool_add(int id, void *data) {
    struct pool_entry *e = kmalloc(sizeof(*e), GFP_KERNEL);
    if (!e) return -ENOMEM;
    e->id = id; e->data = data;
    refcount_set(&e->refs, 1);
    unsigned int hash = hash_32(id, 6);
    spin_lock(&pool.bucket_locks[hash]);
    hlist_add_head_rcu(&e->node, &pool.buckets[hash]);
    spin_unlock(&pool.bucket_locks[hash]);
    return 0;
}

/* Remove */
int pool_remove(int id) {
    struct pool_entry *e;
    unsigned int hash = hash_32(id, 6);
    spin_lock(&pool.bucket_locks[hash]);
    hlist_for_each_entry(e, &pool.buckets[hash], node) {
        if (e->id == id) {
            hlist_del_rcu(&e->node);
            spin_unlock(&pool.bucket_locks[hash]);
            pool_put(e);  /* Drop our reference */
            return 0;
        }
    }
    spin_unlock(&pool.bucket_locks[hash]);
    return -ENOENT;
}
```

Key patterns: (1) RCU for lock-free lookup. (2) refcount_inc_not_zero prevents referencing freed objects. (3) call_rcu defers memory reclamation. (4) Per-bucket locks for writers.

```c
/*
 * Analyze THP usage efficiency by comparing actual
 * THP-backed memory with potential THP memory.
 */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef unsigned long ulong;

struct thp_analysis {
    ulong anon_huge_pages_kb;
    ulong anon_pages_kb;
    ulong thp_fault_alloc;
    ulong thp_fault_fallback;
    ulong thp_collapse_alloc;
    ulong thp_collapse_alloc_failed;
    ulong thp_split_page;
    ulong thp_split_page_failed;
};

static int read_meminfo_field(const char *field, ulong *val)
{
    FILE *f = fopen("/proc/meminfo", "r");
    char line[256], name[64];
    while (fgets(line, sizeof(line), f)) {
        if (sscanf(line, "%63s %lu", name, val) == 2) {
            name[strlen(name)-1] = 0; /* remove ':' */
            if (strcmp(name, field) == 0) {
                fclose(f);
                return 0;
            }
        }
    }
    fclose(f);
    return -1;
}

static ulong read_vmstat(const char *field)
{
    FILE *f = fopen("/proc/vmstat", "r");
    char line[256], name[64];
    ulong val = 0;
    while (fgets(line, sizeof(line), f)) {
        if (sscanf(line, "%63s %lu", name, &val) == 2) {
            if (strcmp(name, field) == 0) {
                fclose(f);
                return val;
            }
        }
    }
    fclose(f);
    return 0;
}

int main(void) {
    struct thp_analysis a;
    double fault_success, collapse_success, split_rate;
    double thp_coverage;

    read_meminfo_field("AnonHugePages", &a.anon_huge_pages_kb);
    read_meminfo_field("AnonPages", &a.anon_pages_kb);
    a.thp_fault_alloc = read_vmstat("thp_fault_alloc");
    a.thp_fault_fallback = read_vmstat("thp_fault_fallback");
    a.thp_collapse_alloc = read_vmstat("thp_collapse_alloc");
    a.thp_collapse_alloc_failed =
        read_vmstat("thp_collapse_alloc_failed");
    a.thp_split_page = read_vmstat("thp_split_page");

    printf("=== THP Analysis ===\n\n");

    /* THP coverage: % of anonymous memory backed by THP */
    if (a.anon_pages_kb > 0) {
        thp_coverage = 100.0 * a.anon_huge_pages_kb /
                       a.anon_pages_kb;
        printf("THP coverage: %.1f%% (%lu MB of %lu MB "
               "anonymous memory)\n",
               thp_coverage,
               a.anon_huge_pages_kb / 1024,
               a.anon_pages_kb / 1024);
    }

    /* Fault allocation success rate */
    ulong total_faults = a.thp_fault_alloc +
                          a.thp_fault_fallback;
    if (total_faults > 0) {
        fault_success = 100.0 * a.thp_fault_alloc /
                        total_faults;
        printf("THP fault success rate: %.1f%% "
               "(%lu alloc, %lu fallback)\n",
               fault_success,
               a.thp_fault_alloc, a.thp_fault_fallback);
    }

    /* Collapse success rate */
    ulong total_collapse = a.thp_collapse_alloc +
                            a.thp_collapse_alloc_failed;
    if (total_collapse > 0) {
        collapse_success = 100.0 * a.thp_collapse_alloc /
                           total_collapse;
        printf("THP collapse success rate: %.1f%% "
               "(%lu alloc, %lu failed)\n",
               collapse_success,
               a.thp_collapse_alloc,
               a.thp_collapse_alloc_failed);
    }

    /* Split rate indicator */
    printf("THP splits: %lu (high value indicates "
           "THP instability)\n", a.thp_split_page);

    /*
     * Interpretation:
     * - Coverage < 20%: THP is not effective. Check defrag
     *   setting and compaction status.
     * - Fault fallback > 50%: Memory fragmentation is
     *   preventing THP allocation. Consider increasing
     *   min_free_kbytes or running compaction.
     * - High split rate: THPs are being split frequently,
     *   indicating COW, mprotect, or munmap on huge pages.
     *   Consider MADV_NOHUGEPAGE for affected regions.
     */

    return 0;
}
```
此工具通过/proc/meminfo和/proc/vmstat的数据分析THP效率。关键指标：THP coverage（匿名内存中THP占比）反映THP的实际使用量；fault fallback rate反映内存碎片化程度；split rate反映THP的稳定性。结合这些信息可以优化THP配置。

handle_fasteoi_irq provides a generic implementation for interrupts,
