priv->buf = dma_alloc_coherent(dev, SZ, &priv->dma, GFP_KERNEL);
init_completion(&priv->done);

writel(lower_32_bits(priv->dma), regs + ADDR_LO);
writel(upper_32_bits(priv->dma), regs + ADDR_HI);
writel(SZ, regs + LEN);
writel(START, regs + CTRL);
