Like folio_put(), but for an array of folios.  This is more efficient
than writing the loop yourself as it will optimise the locks which
need to be taken if the folios are freed.

Context: May be called in process or interrupt context, but not in NMI
context.  May be called while holding a spinlock.

```c
#include <linux/sched.h>
#include <linux/sched/mm.h>
#include <linux/mm.h>

/*
 * Calculate a process's memory footprint as the OOM
 * killer sees it. This mirrors the oom_badness()
 * calculation in mm/oom_kill.c.
 */
static void dump_oom_footprint(struct task_struct *task)
{
    struct mm_struct *mm;
    unsigned long total_pages = totalram_pages();
    unsigned long anon_pages, file_pages, shmem_pages;
    unsigned long swap_pages, total_rss;
    long points;

    if (!task || !task->mm) {
        pr_info("Kernel thread or NULL mm\n");
        return;
    }

    mm = task->mm;

    /* Anonymous pages (heap, stack, COW) */
    anon_pages = get_mm_counter(mm, MM_ANONPAGES);

    /* File-backed pages (mmap, shared libraries) */
    file_pages = get_mm_counter(mm, MM_FILEPAGES);

    /* Shared memory pages (tmpfs, shm) */
    shmem_pages = get_mm_counter(mm, MM_SHMEMPAGES);

    /* Pages currently in swap */
    swap_pages = get_mm_counter(mm, MM_SWAPENTS);

    total_rss = anon_pages + file_pages + shmem_pages;

    pr_info("OOM footprint for PID %d (%s):\n",
            task->pid, task->comm);
    pr_info("  Anonymous (RSS): %8lu pages (%5lu MB)\n",
            anon_pages, anon_pages << (PAGE_SHIFT - 20));
    pr_info("  File-backed:   %8lu pages (%5lu MB)\n",
            file_pages, file_pages << (PAGE_SHIFT - 20));
    pr_info("  Shared memory:  %8lu pages (%5lu MB)\n",
            shmem_pages, shmem_pages << (PAGE_SHIFT - 20));
    pr_info("  Swap usage:    %8lu pages (%5lu MB)\n",
            swap_pages, swap_pages << (PAGE_SHIFT - 20));
    pr_info("  Total RSS:     %8lu pages (%5lu MB)\n",
            total_rss, total_rss << (PAGE_SHIFT - 20));

    /* Calculate OOM score */
    points = (total_rss + swap_pages) * 1000 / total_pages;
    points += task->signal->oom_score_adj;

    if (has_capability_noaudit(task, CAP_SYS_ADMIN))
        points -= (points * 3) / 100;

    if (points < 0) points = 0;
    if (points > 1000) points = 1000;

    pr_info("  OOM badness:   %ld/1000\n", points);
    pr_info("  oom_score_adj: %d\n",
            task->signal->oom_score_adj);
    pr_info("  System total:  %lu pages (%lu MB)\n",
            total_pages, total_pages << (PAGE_SHIFT - 20));

    /*
     * The OOM killer considers this process's contribution
     * to total memory pressure. A score of 500 means the
     * process uses ~50% of system memory. Higher scores
     * make the process more likely to be killed.
     */
}
```
This function replicates the OOM killer's scoring logic. It can be used as a diagnostic tool to understand why a specific process was chosen as an OOM victim. The key insight: the OOM killer considers both RSS and swap usage — a process with large RSS but minimal swap is a better victim than one with small RSS but heavy swap usage (because killing the latter would require swap-in for other processes).

