When walking page tables, the kernel must handle the case where a PUD or PMD entry is a huge page (leaf entry) rather than a pointer to a lower-level table. This requires special checks at each level.

**Standard walk with huge page handling:**
```c
// Walking page tables for address 'addr'
pgd_t *pgd = pgd_offset(mm, addr);
if (pgd_none(*pgd) || pgd_bad(*pgd))
    return NULL;

p4d_t *p4d = p4d_offset(pgd, addr);
if (p4d_none(*p4d))
    return NULL;

pud_t *pud = pud_offset(p4d, addr);
if (pud_none(*pud))
    return NULL;

// CHECK: Is this a 1GB huge page?
if (pud_huge(*pud) || pud_large(*pud)) {
    // PUD is a leaf entry — directly maps 1GB
    // No PMD or PTE tables exist
    return pud_page(*pud) + (addr & PUD_MASK);
}

pmd_t *pmd = pmd_offset(pud, addr);
if (pmd_none(*pmd))
    return NULL;

// CHECK: Is this a 2MB huge page?
if (pmd_huge(*pmd) || pmd_large(*pmd)) {
    // PMD is a leaf entry — directly maps 2MB
    // No PTE table exists
    return pmd_page(*pmd) + (addr & PMD_MASK);
}

// Regular PTE
pte_t *pte = pte_offset(pmd, addr);
if (pte_none(*pte) || !pte_present(*pte))
    return NULL;
return pte_page(*pte) + (addr & PAGE_MASK);
```

**walk_page_range() — generic page table walker:**
```c
int walk_page_range(struct mm_struct *mm, unsigned long start,
                     unsigned long end, const struct mm_walk_ops *ops,
                     void *private)
{
    struct mm_walk walk = {
        .ops = ops,
        .mm = mm,
        .private = private,
    };

    for (addr = start; addr < end; ) {
        // Walk PGD
        pgd = pgd_offset(mm, addr);
        next = pgd_addr_end(addr, end);

        // Walk PUD (checking for 1GB huge)
        pud = pud_offset(pgd, addr);
        if (pud_huge(*pud)) {
            ops->hugetlb_entry(pud, addr, &walk);
            addr = pud_addr_end(addr, end);
            continue;
        }

        // Walk PMD (checking for 2MB huge)
        pmd = pmd_offset(pud, addr);
        if (pmd_huge(*pmd)) {
            ops->hugetlb_entry(pmd, addr, &walk);
            addr = pmd_addr_end(addr, end);
            continue;
        }

        // Walk PTE
        pte = pte_offset(pmd, addr);
        ops->pte_entry(pte, addr, &walk);
        addr += PAGE_SIZE;
    }
}
```

**GUP (get_user_pages) and huge pages:**
GUP handles huge pages by pinning the entire compound page:
```c
static struct page *follow_huge_pmd(struct vm_area_struct *vma,
                                      unsigned long address, pmd_t *pmd)
{
    struct page *page = pmd_page(*pmd);
    // Return the sub-page within the compound page
    page += ((address & PMD_MASK) >> PAGE_SHIFT);
    get_page(compound_head(page));
    return page;
}
```

When data is shared between process context and softirq (bottom half) context, you must use the appropriate spinlock variant to prevent deadlocks.

**The problem**: A softirq can interrupt process context on the same CPU. If process context holds a spinlock and a softirq fires that tries to acquire the same lock, deadlock occurs.

**spin_lock_bh** disables softirq processing on the local CPU while holding the lock:
```c
/* Data shared between process and softirq/tasklet context */
spinlock_t bh_lock;
struct shared_data data;

/* Process context — disable softirqs */
void process_update(void) {
    spin_lock_bh(&bh_lock);
    data.value++;
    spin_unlock_bh(&bh_lock);
}

/* Softirq/tasklet handler */
void softirq_handler(void) {
    /* Plain spin_lock is safe here because:
     * 1. Softirqs cannot nest on the same CPU
     * 2. Process context uses spin_lock_bh, preventing softirq
     *    from running while process holds the lock */
    spin_lock(&bh_lock);
    data.value++;
    spin_unlock(&bh_lock);
}
```

**When to use spin_lock_bh vs spin_lock_irqsave**:
```c
/* Use spin_lock_bh when data is shared with softirq but NOT hardirq */
spin_lock_bh(&lock);    /* Disables softirq, keeps hardirq enabled */

/* Use spin_lock_irqsave when data is shared with hardirq handlers */
spin_lock_irqsave(&lock, flags);  /* Disables ALL interrupts */
```

spin_lock_bh is more efficient than irqsave because it only disables softirq processing (setting a per-CPU counter) without disabling hardware interrupts. This means hardirq latency is not increased.

**Common mistake**:
```c
/* WRONG: Using plain spin_lock in process context when shared with softirq */
void wrong_process_update(void) {
    spin_lock(&bh_lock);      /* No softirq disable! */
    data.value++;
    /* A softirq could fire RIGHT HERE, try to acquire bh_lock, and deadlock */
    spin_unlock(&bh_lock);
}
```

