以下是使用SYSCALL_DEFINE3定义系统调用处理函数的示例：

#include <linux/syscalls.h>
#include <linux/uaccess.h>

SYSCALL_DEFINE3(my_syscall, int, fd, char __user *, buf, size_t, count)
{
    struct fd f;
    char *kbuf;
    long ret;

    /* 验证参数 */
    if (count > PAGE_SIZE)
        return -EINVAL;

    f = fdget(fd);
    if (!f.file)
        return -EBADF;

    kbuf = kmalloc(count, GFP_KERNEL);
    if (!kbuf) {
        ret = -ENOMEM;
        goto out;
    }

    /* 从用户空间安全拷贝 */
    if (copy_from_user(kbuf, buf, count)) {
        ret = -EFAULT;
        goto out_free;
    }

    /* 处理数据... */
    ret = count;

out_free:
    kfree(kbuf);
out:
    fdput(f);
    return ret;
}

