```c
/* Tracepoint-based approach to monitor CFS vruntime evolution */
/* Add custom tracepoint or use existing sched:sched_stat_runtime */

#include <trace/events/sched.h>

/* Existing tracepoint in kernel/sched/fair.c update_curr(): */
/* trace_sched_stat_runtime(p, delta_exec, vruntime); */

/* Custom ftrace function to hook update_curr */
static void probe_sched_stat_runtime(void *data,
    struct task_struct *p, u64 delta_exec, u64 vruntime)
{
    /* Log: comm, pid, CPU, delta_exec (ns), vruntime (ns) */
    if (p->pid == target_pid) {
        trace_printk("pid=%d cpu=%d delta=%llu vruntime=%llu "
                     "weight=%lu min_vr=%llu\n",
            p->pid, task_cpu(p),
            delta_exec, vruntime,
            p->se.load.weight,
            cfs_rq_of(&p->se)->min_vruntime);
    }
}

/* Module init — register probe */
static int __init trace_init(void)
{
    register_trace_sched_stat_runtime(
        probe_sched_stat_runtime, NULL);
    return 0;
}

/* Alternatively, use bpftrace: */
/* bpftrace -e 'kprobe:update_curr { 
    @[comm, pid] = stats(arg1); }' */
```

The vruntime delta is delta_exec * NICE_0_LOAD / se.load.weight. Monitoring these values reveals whether tasks with different nice values are getting proportional CPU time and whether min_vruntime advances at the expected rate.

