Here's a complete implementation of a seccomp-BPF filter that allows only `read()`, `write()`, `exit()`, `exit_group()`, `openat()`, and `close()` system calls, blocking everything else with SIGSYS.

**Userspace Implementation**:
```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/prctl.h>
#include <linux/seccomp.h>
#include <linux/filter.h>
#include <linux/audit.h>
#include <stddef.h>

// Helper macros for BPF instructions
#define ALLOW BPF_STMT(BPF_RET | BPF_K, SECCOMP_RET_ALLOW)
#define DENY  BPF_STMT(BPF_RET | BPF_K, SECCOMP_RET_KILL_THREAD)

// Load syscall number from seccomp_data
#define LOAD_SYSCALL_NR \
    BPF_STMT(BPF_LD | BPF_W | BPF_ABS, offsetof(struct seccomp_data, nr))

// Allow if syscall number matches
#define ALLOW_SYSCALL(nr) \
    BPF_JUMP(BPF_JMP | BPF_JEQ | BPF_K, nr, 0, 1), \
    ALLOW

int install_seccomp_filter(void) {
    struct sock_filter filter[] = {
        // Validate architecture (prevent 32-bit syscall confusion attacks)
        BPF_STMT(BPF_LD | BPF_W | BPF_ABS,
                 offsetof(struct seccomp_data, arch)),
        BPF_JUMP(BPF_JMP | BPF_JEQ | BPF_K, AUDIT_ARCH_X86_64, 1, 0),
        DENY,

        // Load syscall number
        LOAD_SYSCALL_NR,

        // Allow list
        ALLOW_SYSCALL(__NR_read),
        ALLOW_SYSCALL(__NR_write),
        ALLOW_SYSCALL(__NR_openat),
        ALLOW_SYSCALL(__NR_close),
        ALLOW_SYSCALL(__NR_exit),
        ALLOW_SYSCALL(__NR_exit_group),

        // Default: deny with SIGSYS
        DENY,
    };

    struct sock_fprog prog = {
        .len = sizeof(filter) / sizeof(filter[0]),
        .filter = filter,
    };

    // Set NO_NEW_PRIVS (required for unprivileged seccomp)
    if (prctl(PR_SET_NO_NEW_PRIVS, 1, 0, 0, 0) < 0) {
        perror("prctl(NO_NEW_PRIVS)");
        return -1;
    }

    // Install the filter
    if (prctl(PR_SET_SECCOMP, SECCOMP_MODE_FILTER, &prog) < 0) {
        perror("prctl(SECCOMP)");
        return -1;
    }

    return 0;
}

int main(void) {
    char buf[256];
    int fd;

    // Install filter BEFORE doing anything restricted
    if (install_seccomp_filter() < 0)
        return 1;

    // These operations are ALLOWED:
    const char *msg = "Hello from sandbox!\n";
    write(STDOUT_FILENO, msg, strlen(msg));

    fd = openat(AT_FDCWD, "/etc/hostname", O_RDONLY);
    if (fd >= 0) {
        ssize_t n = read(fd, buf, sizeof(buf) - 1);
        if (n > 0) {
            buf[n] = '\0';
            write(STDOUT_FILENO, buf, n);
        }
        close(fd);
    }

    // This would cause SIGSYS (blocked):
    // fork();       // NOT ALLOWED
    // mmap(...);    // NOT ALLOWED
    // execve(...);  // NOT ALLOWED

    return 0;
}
```

**Advanced: Filtering openat() Arguments**:
```c
// Restrict openat to read-only (O_RDONLY = 0, O_RDONLY|O_CLOEXEC = 0x80000)
struct sock_filter filter[] = {
    // ... architecture check and LOAD_SYSCALL_NR ...

    // For openat specifically, check the flags argument (arg[2])
    BPF_JUMP(BPF_JMP | BPF_JEQ | BPF_K, __NR_openat, 0, 4),
    BPF_STMT(BPF_LD | BPF_W | BPF_ABS,
             offsetof(struct seccomp_data, args[2])),
    // Mask out O_CLOEXEC (0x80000) and check for write bits
    BPF_STMT(BPF_ALU | BPF_AND | BPF_K, O_WRONLY | O_RDWR | O_CREAT | O_TRUNC),
    BPF_JUMP(BPF_JMP | BPF_JEQ | BPF_K, 0, 0, 1),
    ALLOW,
    BPF_STMT(BPF_RET | BPF_K, SECCOMP_RET_ERRNO | EACCES),
};
```

**Key Points**:
1. Always validate the architecture first to prevent 32-bit confusion attacks
2. Use `PR_SET_NO_NEW_PRIVS` before installing filters
3. Filters persist across `fork()` and `execve()`
4. Multiple filters stack with AND semantics
5. Use libseccomp (`seccomp_init()`, `seccomp_rule_add()`) for production code instead of raw BPF

