On 32-bit architectures, 64-bit atomic operations cannot be performed with a single instruction. The kernel provides different implementations depending on the architecture.

**Generic implementation using spinlock**:
```c
/* Fallback: spinlock-protected 64-bit operations */
typedef struct {
    raw_spinlock_t lock;
    long long counter;
} atomic64_t;

static inline long long atomic64_read(atomic64_t *v) {
    unsigned long flags;
    long long val;
    raw_spin_lock_irqsave(&v->lock, flags);
    val = v->counter;
    raw_spin_unlock_irqrestore(&v->lock, flags);
    return val;
}

static inline void atomic64_add(long long a, atomic64_t *v) {
    unsigned long flags;
    raw_spin_lock_irqsave(&v->lock, flags);
    v->counter += a;
    raw_spin_unlock_irqrestore(&v->lock, flags);
}
```

**ARM 32-bit implementation**:
```c
/* ARM uses LDREXD/STREXD (64-bit exclusive access) */
static inline long long atomic64_add_return(long long i, atomic64_t *v) {
    long long result;
    unsigned long tmp;
    asm volatile(
        "1: ldrexd %0, %H0, [%3]\n"
        "   adds %0, %0, %4\n"
        "   strexd %1, %0, %H0, [%3]\n"
        "   teq %1, #0\n"
        "   bne 1b"
        : "=&r" (result), "=&r" (tmp), "+Qo" (v->counter)
        : "r" (&v->counter), "r" (i)
        : "cc");
    return result;
}
```

**x86 32-bit implementation**:
```c
/* x86 uses CMPXCHG8B for 64-bit CAS */
static inline long long atomic64_cmpxchg(atomic64_t *v, long long old, long long new) {
    /* CMPXCHG8B: compare EDX:EAX with m64, if equal store ECX:EBX */
    asm volatile("lock cmpxchg8b %1"
        : "+A" (old), "+m" (v->counter)
        : "b" ((unsigned long)new), "c" ((unsigned long)(new >> 32))
        : "memory");
    return old;
}
```

On 64-bit architectures, atomic64_t maps directly to native 64-bit atomic instructions with no overhead difference from atomic_t.

