```c
#include <asm/fixmap.h>
#include <asm/io.h>

/*
 * Read a 32-bit value from a physical address using fixmap.
 * This is useful during early boot before ioremap is available.
 */
static u32 read_phys_via_fixmap(phys_addr_t phys_addr, enum fixed_addresses idx)
{
    void __iomem *vaddr;
    u32 value;

    /* Map the physical page to the fixmap slot */
    set_fixmap(idx, phys_addr & PAGE_MASK);

    /* Compute the virtual address with page offset */
    vaddr = (void __iomem *)fix_to_virt(idx) + (phys_addr & ~PAGE_MASK);

    /* Read the 32-bit value using proper I/O accessor */
    value = readl(vaddr);

    /* Clear the fixmap mapping when done */
    clear_fixmap(idx);

    return value;
}

/*
 * Example usage during early boot:
 * Read from a known hardware register at physical 0xFED00000
 * (e.g., HPET base register)
 */
static void __init example_fixmap_usage(void)
{
    u32 hpet_id = read_phys_via_fixmap(0xFED00000, FIX_BTMAP_0);
    pr_info("HPET ID register: 0x%08x\n", hpet_id);
}
```

The `fix_to_virt(idx)` macro converts the fixmap index to a virtual address. `set_fixmap()` installs a PTE mapping, and `readl()` performs an MMIO read with appropriate memory barriers. Always pair `set_fixmap()` with `clear_fixmap()` to avoid stale mappings.

