/* 从内核空间执行用户空间程序 */
static int run_userspace_helper(const char *path, const char *arg)
{
    char *argv[] = { (char *)path, (char *)arg, NULL };
    static char *envp[] = {
        "HOME=/",
        "TERM=linux",
        "PATH=/sbin:/bin:/usr/sbin:/usr/bin",
        NULL
    };
    int ret;

    /* UMH_WAIT_EXEC: 等待exec完成，不等待程序退出 */
    ret = call_usermodehelper(argv[0], argv, envp, UMH_WAIT_EXEC);
    if (ret < 0) {
        pr_err("Failed to exec %s: %d\n", argv[0], ret);
        return ret;
    }

    /* UMH_WAIT_PROC: 等待程序完全执行完毕 */
    /* ret = call_usermodehelper(argv[0], argv, envp, UMH_WAIT_PROC); */

    pr_info("Successfully launched %s\n", argv[0]);
    return 0;
}

/* 使用call_usermodehelper_setup()进行更精细的控制 */
static int run_with_setup(void)
{
    struct subprocess_info *info;
    char *argv[] = { "/usr/bin/logger", "-t", "kernel", "hello", NULL };
    static char *envp[] = { "HOME=/", "PATH=/sbin:/bin", NULL };

    info = call_usermodehelper_setup(argv[0], argv, envp,
                                      GFP_KERNEL,
                                      NULL,  /* init */
                                      NULL,  /* cleanup */
                                      NULL); /* data */
    if (!info)
        return -ENOMEM;

    /* UMH_WAIT_PROC返回子进程的退出码 */
    return call_usermodehelper_exec(info, UMH_WAIT_PROC);
}
