```c
#include <linux/seqlock.h>
#include <linux/slab.h>
#include <asm/barrier.h>

/*
 * Memory-ordered ring buffer using seqlock for
 * reader-writer synchronization.
 *
 * Seqlock allows multiple concurrent readers with a
 * single writer. Readers detect conflicts and retry.
 */
#define RING_CAPACITY 256

struct ordered_ring {
    seqlock_t lock;
    int data[RING_CAPACITY];
    unsigned int head;    /* Writer advances */
    unsigned int tail;    /* Reader follows */
    unsigned long seq;    /* Sequence counter */
};

static struct ordered_ring *oring;

/*
 * Writer: add data to the ring.
 * Uses seqlock to protect concurrent updates.
 */
static int oring_write(int value)
{
    unsigned int next;

    /*
     * write_seqlock() takes the spinlock AND increments
     * the sequence counter (odd value = write in progress).
     * This provides a full memory barrier.
     */
    write_seqlock(&oring->lock);

    next = (oring->head + 1) % RING_CAPACITY;
    if (next == oring->tail) {
        write_sequnlock(&oring->lock);
        return -ENOSPC; /* Ring full */
    }

    oring->data[oring->head] = value;

    /*
     * smp_wmb() ensures data write is visible before
     * the head advance. Combined with seqlock's barrier,
     * this is redundant but demonstrates the principle.
     */
    smp_wmb();
    oring->head = next;

    /*
     * write_sequnlock() increments sequence counter again
     * (even value = stable) and releases spinlock.
     * Provides a release barrier.
     */
    write_sequnlock(&oring->lock);
    return 0;
}

/*
 * Reader: read data from the ring.
 * Uses seqlock retry mechanism for lock-free reads.
 */
static int oring_read(int *value)
{
    unsigned int seq, head, tail;
    int data;

    do {
        /*
         * read_seqbegin() reads the sequence counter
         * and provides an acquire barrier. If the counter
         * is odd, a writer is active — we'll retry.
         */
        seq = read_seqbegin(&oring->lock);

        tail = oring->tail;
        head = oring->head;

        /*
         * smp_rmb() ensures we read head AFTER the
         * sequence counter. Without this, we might
         * see a stale head value.
         */
        smp_rmb();

        if (head == tail)
            return -ENODATA; /* Ring empty */

        /* Read the data at tail */
        data = oring->data[tail];

        /*
         * smp_rmb() ensures we read data BEFORE
         * checking the sequence counter again.
         */
        smp_rmb();

    } while (read_seqretry(&oring->lock, seq));
    /*
     * read_seqretry() checks if the sequence counter
     * changed since read_seqbegin(). If it did, a writer
     * modified the ring during our read — we must retry.
     */

    *value = data;

    /* Advance tail (single reader assumed) */
    smp_wmb();
    oring->tail = (tail + 1) % RING_CAPACITY;

    return 0;
}

static int __init oring_init(void)
{
    oring = kzalloc(sizeof(*oring), GFP_KERNEL);
    if (!oring) return -ENOMEM;
    seqlock_init(&oring->lock);
    return 0;
}
```
Seqlock provides efficient read-mostly synchronization: readers never block (they retry on conflict), and the writer takes only a brief spinlock. The memory barriers in read_seqbegin/read_seqretry ensure readers see consistent snapshots. This pattern is used extensively in the kernel for time-of-day counters, filesystem statistics, and routing tables.

```c
#include <linux/fs.h>
#include <linux/fdtable.h>
#include <linux/file.h>

/*
 * Inspect the I/O configuration of an open file descriptor.
 * Check if O_DIRECT is set and analyze the I/O path.
 */
static void inspect_fd_io(int fd)
{
    struct file *filp;
    struct inode *inode;
    unsigned int flags;

    /* Get the file structure from fd */
    filp = fget(fd);
    if (!filp) {
        pr_err("Invalid fd: %d\n", fd);
        return;
    }

    flags = filp->f_flags;
    inode = file_inode(filp);

    pr_info("FD %d inspection:\n", fd);
    pr_info("  Flags: O_DIRECT=%d, O_SYNC=%d, O_DSYNC=%d, "
            "O_APPEND=%d\n",
            !!(flags & O_DIRECT),
            !!(flags & O_SYNC),
            !!(flags & O_DSYNC),
            !!(flags & O_APPEND));

    if (flags & O_DIRECT) {
        pr_info("  I/O path: Direct I/O\n");
        pr_info("    write() -> generic_file_write_iter()\n");
        pr_info("      -> iomap_dio_rw() (for iomap-based fs)\n");
        pr_info("      -> iov_iter_get_pages() (pin user pages)\n");
        pr_info("      -> bio_alloc() + submit_bio()\n");
        pr_info("    No page cache involvement\n");
    } else {
        pr_info("  I/O path: Buffered I/O\n");
        pr_info("    write() -> generic_perform_write()\n");
        pr_info("      -> page cache lookup (xarray)\n");
        pr_info("      -> copy data to cached page\n");
        pr_info("      -> mark page dirty\n");
        pr_info("    Async writeback by kworker/flush\n");
    }

    pr_info("  Filesystem: %s\n",
            inode->i_sb->s_type->name);
    pr_info("  Block size: %u\n", inode->i_sb->s_blocksize);

    /*
     * Check alignment requirements for O_DIRECT:
     * Buffer address, size, and file offset must all be
     * aligned to the logical block size.
     */
    if (flags & O_DIRECT) {
        pr_info("  Required alignment: %u bytes\n",
                bdev_logical_block_size(inode->i_sb->s_bdev));
    }

    fput(filp);
}
```
This function uses fget() to obtain the file structure from the fd table, then inspects f_flags for I/O mode indicators. The actual I/O dispatch path depends on the filesystem's file_operations: ext4 uses ext4_file_write_iter which branches on O_DIRECT, XFS uses xfs_file_write_iter, etc.

