kthread_worker provides a dedicated kernel thread that processes work items sequentially:

```c
#include <linux/kthread.h>

/* Define a worker and work items */
static struct kthread_worker *my_worker;
static struct kthread_work my_work;

/* Work handler function */
static void my_work_handler(struct kthread_work *work)
{
    /* Process the work item — runs in kworker context */
    pr_info("Processing work item\n");
}

/* Initialization */
static int __init my_module_init(void)
{
    /* Create a kthread_worker — spawns a kernel thread */
    my_worker = kthread_create_worker(0, "my_worker");
    if (IS_ERR(my_worker))
        return PTR_ERR(my_worker);

    /* Initialize work item with handler */
    kthread_init_work(&my_work, my_work_handler);

    /* Queue work — kthread thread will execute it */
    kthread_queue_work(my_worker, &my_work);
    return 0;
}

/* Cleanup — flush and destroy */
static void __exit my_module_exit(void)
{
    /* Flush ensures all queued work completes */
    kthread_flush_worker(my_worker);
    /* Destroy stops the kthread */
    kthread_destroy_worker(my_worker);
}
```

kthread_worker (kernel/kthread.c) differs from workqueues: it provides a single dedicated thread with deterministic scheduling, used by block layer (blk-mq), dm-crypt, and I/O schedulers where workqueue's shared thread pool is unsuitable.

