Implementing connection timeouts with timerfd and epoll:

#include <sys/epoll.h>
#include <sys/timerfd.h>
#include <sys/socket.h>
#include <time.h>
#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>

#define TIMEOUT_MS 5000

struct connection {
    int fd;
    int timer_fd;
    time_t last_active;
};

int set_timeout(struct connection *conn, int timeout_ms)
{
    struct itimerspec its = {
        .it_value = { .tv_sec = timeout_ms / 1000,
                      .tv_nsec = (timeout_ms % 1000) * 1000000L },
        .it_interval = { 0, 0 } /* One-shot */
    };
    return timerfd_settime(conn->timer_fd, 0, &its, NULL);
}

void event_loop(int listen_fd)
{
    int epfd = epoll_create1(EPOLL_CLOEXEC);

    /* Monitor listen socket */
    struct epoll_event ev = { .events = EPOLLIN, .data.ptr = NULL };
    epoll_ctl(epfd, EPOLL_CTL_ADD, listen_fd, &ev);

    struct epoll_event events[64];
    while (1) {
        int n = epoll_wait(epfd, events, 64, 1000);
        for (int i = 0; i < n; i++) {
            struct connection *conn = events[i].data.ptr;
            if (!conn) {
                /* New connection */
                int cfd = accept4(listen_fd, NULL, NULL, SOCK_NONBLOCK);
                conn = calloc(1, sizeof(*conn));
                conn->fd = cfd;
                conn->timer_fd = timerfd_create(CLOCK_MONOTONIC,
                                                 TFD_NONBLOCK | TFD_CLOEXEC);
                set_timeout(conn, TIMEOUT_MS);

                ev.events = EPOLLIN; ev.data.ptr = conn;
                epoll_ctl(epfd, EPOLL_CTL_ADD, cfd, &ev);
                ev.events = EPOLLIN; ev.data.ptr = conn;
                epoll_ctl(epfd, EPOLL_CTL_ADD, conn->timer_fd, &ev);
            } else {
                uint64_t exp;
                if (read(conn->timer_fd, &exp, 8) > 0) {
                    /* Timeout! Close connection */
                    printf("Connection %d timed out
", conn->fd);
                    epoll_ctl(epfd, EPOLL_CTL_DEL, conn->fd, NULL);
                    epoll_ctl(epfd, EPOLL_CTL_DEL, conn->timer_fd, NULL);
                    close(conn->fd);
                    close(conn->timer_fd);
                    free(conn);
                } else {
                    /* Data arrived - reset timeout */
                    set_timeout(conn, TIMEOUT_MS);
                    handle_data(conn->fd);
                }
            }
        }
    }
}

Each connection has its own timerfd for idle timeout. When data arrives, the timer is reset. When the timer fires, the connection is closed. Using CLOCK_MONOTONIC ensures timeouts are unaffected by wall-clock adjustments.

`usb_device_driver` 定义在 `include/linux/usb.h` 中，属于 Linux 内核的 内核核心 子系统。

struct identifies USB device driver to usbcore
@name: The driver name should be unique among USB drivers,
and should normally be the same as the module name.
@match: If set, used for better device/driver matching.
@probe: Called to see if the driver is willing to manage a particular
device.  If it is, probe returns zero and uses dev_set_drvdata()
to associate driver-specific data with the device.  If unwilling
to manage the device, return a negative errno value.
@disconnect: Called when the device is no longer accessible, usually
because it has been (or is being) disconnected or the driver's
module is being unloaded.
@suspend: Called when the device is going to be suspended by the system.
@resume: Called when the device is being resumed by the system.
@dev_groups: Attributes attached to the device that will be created once it
is bound to the driver.
@drvwrap: Driver-model core structure wrapper.
@id_table: used with @match() to select better matching driver at
	probe() time.
@supports_autosuspend: if set to 0, the USB core will not allow autosuspend
for devices bound to this driver.
@generic_subclass: if set to 1, the generic USB driver's probe, disconnect,
resume and suspend functions will be called in addition to the driver's
own, so this part of the setup does not need to be replicated.

参数说明：
- `name`: The driver name should be unique among USB drivers, and should normally be the same as the module name.
- `match`: If set, used for better device/driver matching.
- `probe`: Called to see if the driver is willing to manage a particular device. If it is, probe returns zero and uses dev_set_drvdata() to associate driver-spec
- `disconnect`: Called when the device is no longer accessible, usually because it has been (or is being) disconnected or the driver's module is being unloaded.
- `suspend`: Called when the device is going to be suspended by the system.

