Here is a kernel module that provides multiple methods to trigger different types of kernel oops for debugging practice:

```c
// oops_trigger.c - Educational module for practicing oops analysis
#include <linux/module.h>
#include <linux/kernel.h>
#include <linux/init.h>
#include <linux/fs.h>
#include <linux/uaccess.h>

MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("Oops trigger module for debugging practice");

static int *null_ptr = NULL;

/* Trigger NULL pointer dereference */
static void trigger_null_deref(void)
{
    pr_info("Triggering NULL pointer dereference...\n");
    /* This will cause a page fault in kernel mode */
    *null_ptr = 42;
}

/* Trigger use-after-free */
static void trigger_use_after_free(void)
{
    char *buf = kmalloc(128, GFP_KERNEL);
    if (!buf)
        return;
    strcpy(buf, "Hello kernel");
    kfree(buf);
    pr_info("Triggering use-after-free...\n");
    /* Access freed memory - may or may not oops depending on slab state */
    pr_info("Freed content: %s\n", buf);
    buf[0] = 'X'; /* write to freed memory */
}

/* Trigger stack overflow */
static void trigger_stack_overflow(void)
{
    volatile char large_buf[4096];
    pr_info("Triggering stack overflow...\n");
    /* Recursive call consuming stack space */
    large_buf[0] = 1;
    trigger_stack_overflow();
}

/* Trigger BUG_ON */
static void trigger_bug_on(void)
{
    pr_info("Triggering BUG_ON...\n");
    BUG_ON(1);
}

static int __init oops_trigger_init(void)
{
    pr_info("oops_trigger loaded. Write 1-4 to /dev/oops_trigger:\n");
    pr_info("  1 = NULL deref, 2 = UAF, 3 = stack overflow, 4 = BUG_ON\n");
    return 0;
}
```

To use: load the module, then call the trigger functions (e.g., via a /proc or /sys interface, or debugfs). Analyze the resulting oops with: `dmesg` to capture the full output, `addr2line -e vmlinux <address>` to find source lines, and `scripts/decodecode` to disassemble the Code: line. WARNING: Only use in virtual machines or test systems — these triggers can crash the system.

使用libseccomp创建限制系统调用的BPF过滤器：

#include <seccomp.h>
#include <unistd.h>
#include <errno.h>

int install_seccomp_filter()
{
    scmp_filter_ctx ctx;

    /* 默认策略：杀死进程 */
    ctx = seccomp_init(SCMP_ACT_KILL_PROCESS);
    if (!ctx) return -1;

    /* 允许的系统调用 */
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(read), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(write), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(exit_group), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(brk), 0);

    /* 对open返回EPERM而非杀死 */
    seccomp_rule_add(ctx, SCMP_ACT_ERRNO(EPERM), SCMP_SYS(open), 0);
    seccomp_rule_add(ctx, SCMP_ACT_ERRNO(EPERM), SCMP_SYS(openat), 0);

    /* 带参数的过滤：只允许write到fd 1(stdout)和2(stderr) */
    seccomp_rule_add(ctx, SCMP_ACT_ALLOW, SCMP_SYS(write), 1,
        SCMP_A0(SCMP_CMP_EQ, 1)); /* fd == 1 */

    int rc = seccomp_load(ctx);
    seccomp_release(ctx);
    return rc;
}

seccomp_init()设置默认动作。seccomp_rule_add()添加规则。seccomp_load()编译BPF程序并通过prctl(PR_SET_SECCOMP)安装。一旦安装，过滤器不可移除，仅可添加更多。子进程通过fork继承过滤器。

