```c
#include <linux/mempool.h>
#include <linux/slab.h>
#include <linux/bio.h>

/*
 * mempool_t guarantees that a minimum number of objects
 * are always available for allocation, even under memory
 * pressure. Used in I/O paths where allocation failure
 * is unacceptable.
 */

struct my_request {
    u64 id;
    void *data;
    size_t size;
    struct list_head list;
};

static mempool_t *req_pool;
#define MIN_REQ_POOL_SIZE 32

/*
 * Custom allocator for mempool.
 * Called when the pool needs to grow.
 */
static void *my_req_alloc(gfp_t gfp_mask, void *pool_data)
{
    /*
     * Use kmalloc with the provided gfp_mask.
     * mempool adjusts the flags: when the pool has
     * reserved elements, it uses __GFP_NORETRY to
     * avoid excessive reclaim.
     */
    return kmalloc(sizeof(struct my_request), gfp_mask);
}

/* Custom deallocator for mempool */
static void my_req_free(void *element, void *pool_data)
{
    kfree(element);
}

static int __init my_module_init(void)
{
    /*
     * Create the mempool with MIN_REQ_POOL_SIZE
     * pre-allocated elements. These elements are
     * always available — mempool_alloc will never
     * fail if fewer than MIN elements are outstanding.
     */
    req_pool = mempool_create(MIN_REQ_POOL_SIZE,
                               my_req_alloc,
                               my_req_free,
                               NULL);
    if (!req_pool)
        return -ENOMEM;

    /*
     * Alternative: use kmalloc-based mempool:
     * req_pool = mempool_create_kmalloc_pool(
     *     MIN_REQ_POOL_SIZE,
     *     sizeof(struct my_request));
     *
     * For page-based pools:
     * page_pool = mempool_create_page_pool(MIN_PAGES, 0);
     *
     * For bio pools (block layer):
     * bio_pool = mempool_create_bio_pool(MIN_BIOS);
     */

    return 0;
}

/*
 * Allocate from the mempool.
 * Guaranteed to succeed (may block waiting for a
 * freed element to return to the pool).
 */
static struct my_request *get_request(void)
{
    struct my_request *req;

    /*
     * mempool_alloc():
     * 1. Try to allocate from the reserve pool
     *    (pre-allocated elements)
     * 2. If reserve is empty, call the alloc function
     *    with GFP_NOIO (limited reclaim)
     * 3. If that fails too, sleep and wait for an
     *    element to be returned to the pool
     *
     * This guarantees forward progress even under
     * extreme memory pressure.
     */
    req = mempool_alloc(req_pool, GFP_NOIO);
    if (!req)
        return NULL; /* Only if signal pending */

    memset(req, 0, sizeof(*req));
    return req;
}

/* Return an element to the pool */
static void put_request(struct my_request *req)
{
    mempool_free(req, req_pool);
}

static void __exit my_module_exit(void)
{
    mempool_destroy(req_pool);
}
```
mempool is essential in I/O paths (block layer, filesystems, network) where allocation failure would cause deadlock or data loss. By pre-allocating a minimum number of elements, it ensures forward progress even when the system is under memory pressure and regular allocations would fail.

`struct inode` (include/linux/fs.h) represents a filesystem object:
```c
struct inode {
    umode_t i_mode;           // file type + permissions
    kuid_t i_uid; kgid_t i_gid;
    unsigned int i_flags;     // S_IMMUTABLE, S_APPEND
    unsigned long i_ino;      // inode number
    unsigned int i_nlink;     // hard link count
    loff_t i_size;
    struct timespec64 i_atime, i_mtime, i_ctime;
    blkcnt_t i_blocks;
    struct address_space i_data;
    const struct inode_operations *i_op;
    struct super_block *i_sb;
};
```
i_mode encodes type (S_IFREG, S_IFDIR, S_IFLNK...) and permissions. Filesystem-specific data via container_of: EXT4_I(), BTRFS_I(), XFS_I().

Filesystem-specific inode data is accessed through `container_of()` macros. For ext4, `EXT4_I(inode)` returns `struct ext4_inode_info` containing extent tree roots, preallocation state, and ext4-specific flags. For XFS, `XFS_I(inode)` returns `struct xfs_inode` with fork structures for data and attributes. For btrfs, `BTRFS_I(inode)` provides generation numbers and extent map references. This embedding pattern allows the VFS inode and filesystem-specific data to share a single cache line, improving access locality. The slab allocator (`inode_cachep`) manages inode memory with hardware cache-line alignment for optimal performance.

The inode cache management involves several interacting subsystems. The inode hash table provides O(1) lookup by inode number within a superblock. The LRU list tracks unused inodes for memory reclamation. The dirty list coordinates writeback timing. The slab allocator provides fast allocation with cache-line alignment. When memory pressure occurs, the inode shrinker evicts unused inodes from the LRU, first writing back any dirty metadata via `write_inode()`. The `iput()` function handles the complex lifecycle: decrementing the reference count, checking for deletion (nlink==0), and coordinating with the shrinker. RCU-deferred freeing ensures that concurrent RCU readers accessing the inode complete before memory is reused.

