Race-free process management using pidfd:

#include <sys/syscall.h>
#include <sys/wait.h>
#include <poll.h>
#include <signal.h>
#include <unistd.h>
#include <stdio.h>

static int pidfd_open(pid_t pid, unsigned int flags)
{
    return syscall(SYS_pidfd_open, pid, flags);
}

static int pidfd_send_signal(int pidfd, int sig, siginfo_t *info, unsigned int flags)
{
    return syscall(SYS_pidfd_send_signal, pidfd, sig, info, flags);
}

int main()
{
    pid_t child = fork();
    if (child == 0) {
        sleep(5); /* Child work */
        _exit(42);
    }

    /* Get pidfd - immune to PID reuse */
    int pidfd = pidfd_open(child, 0);
    if (pidfd < 0) { perror("pidfd_open"); return 1; }

    /* Poll for child exit */
    struct pollfd pfd = { .fd = pidfd, .events = POLLIN };
    int ret = poll(&pfd, 1, 3000); /* 3s timeout */

    if (ret > 0 && (pfd.revents & POLLIN)) {
        /* Child exited - collect status */
        siginfo_t info = { .si_pid = 0 };
        int status;
        waitid(P_PIDFD, pidfd, &info, WEXITED);
        printf("Child exited with status %d
", info.si_status);
    } else if (ret == 0) {
        /* Timeout - send signal safely */
        pidfd_send_signal(pidfd, SIGTERM, NULL, 0);
        printf("Sent SIGTERM to child
");
    }

    close(pidfd);
    return 0;
}

pidfd_open() returns a file descriptor referring to the process. Unlike PIDs, pidfds remain valid even after the process exits and its PID is reassigned. poll() on the pidfd returns POLLIN when the process exits. pidfd_send_signal() sends a signal without PID reuse races.

