```c
#include <linux/pagemap.h>
#include <linux/fs.h>
#include <linux/backing-dev.h>

/*
 * Simplified readahead logic showing how the kernel
 * proactively reads pages for sequential access.
 *
 * The real implementation is in page_cache_ra_unbounded()
 * and ondemand_readahead().
 */

/*
 * Check if sequential read pattern is detected and
 * trigger readahead if appropriate.
 */
static void check_and_readahead(struct file *filp,
                                 struct address_space *mapping,
                                 pgoff_t index)
{
    struct file_ra_state *ra = &filp->f_ra;
    unsigned long ra_pages;
    pgoff_t start;
    int i;

    /*
     * ra_pages: maximum readahead window, typically
     * bdi->ra_pages (128KB to 2MB depending on device)
     */
    ra_pages = mapping->host->i_mapping->ra_pages;

    /*
     * Detect sequential access pattern:
     * If the current read is at prev_index + 1,
     * it's sequential — trigger readahead.
     */
    if (index == ra->prev_pos >> PAGE_SHIFT) {
        /* Sequential: grow the readahead window */
        ra->size = min(ra->size * 2, ra_pages);
    } else {
        /* Random: use minimum readahead */
        ra->size = 1; /* Single page */
    }

    /* Start readahead from the next page after current */
    start = index + 1;

    /*
     * Submit read-ahead I/O for ra->size pages.
     * The real code uses page_cache_ra_unbounded()
     * which calls mapping->a_ops->readahead().
     */
    for (i = 0; i < ra->size; i++) {
        struct folio *folio;

        /* Check if page is already in cache */
        folio = filemap_get_folio(mapping, start + i);
        if (!IS_ERR(folio)) {
            folio_put(folio); /* Already cached */
            continue;
        }

        /* Allocate and add to page cache */
        folio = filemap_alloc_folio(GFP_KERNEL, 0);
        if (!folio)
            break;

        filemap_add_folio(mapping, folio, start + i,
                          GFP_KERNEL);

        /*
         * Submit the actual I/O.
         * mapping->a_ops->readahead() handles the
         * batch submission to the block layer.
         */
    }

    ra->prev_pos = (loff_t)(index + 1) << PAGE_SHIFT;
}
```
The readahead state (file_ra_state) is per-file-descriptor and tracks access patterns. For sequential reads, the window grows exponentially up to ra_pages. For random reads, readahead is minimized to avoid wasting I/O on data that won't be accessed.

以下使用epoll监控多个fd的C代码示例：

#include <sys/epoll.h>
#include <unistd.h>

#define MAX_EVENTS 64

int event_loop(int listen_fd, int *client_fds, int nclients)
{
    int epfd = epoll_create1(EPOLL_CLOEXEC);
    if (epfd < 0) return -1;

    struct epoll_event ev;
    ev.events = EPOLLIN;
    ev.data.fd = listen_fd;
    epoll_ctl(epfd, EPOLL_CTL_ADD, listen_fd, &ev);

    for (int i = 0; i < nclients; i++) {
        ev.events = EPOLLIN | EPOLLET; /* 边缘触发 */
        ev.data.fd = client_fds[i];
        epoll_ctl(epfd, EPOLL_CTL_ADD, client_fds[i], &ev);
    }

    struct epoll_event events[MAX_EVENTS];
    while (1) {
        int nfds = epoll_wait(epfd, events, MAX_EVENTS, -1);
        for (int i = 0; i < nfds; i++) {
            if (events[i].data.fd == listen_fd) {
                int cfd = accept4(listen_fd, NULL, NULL, SOCK_NONBLOCK);
                ev.events = EPOLLIN | EPOLLET;
                ev.data.fd = cfd;
                epoll_ctl(epfd, EPOLL_CTL_ADD, cfd, &ev);
            } else {
                handle_client(events[i].data.fd);
            }
        }
    }
    close(epfd);
    return 0;
}

