```c
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>

/*
 * Use /proc/pid/pagemap to inspect the virtual-to-physical
 * page mapping of a process.
 *
 * Each 8-byte entry in pagemap corresponds to one virtual
 * page (at the process's page index):
 *   Bits 0-54:  PFN (if page is present)
 *   Bit 55:     soft-dirty
 *   Bit 56:     exclusively mapped
 *   Bit 57:     file-backed / shared anon
 *   Bit 61:     swapped
 *   Bit 62:     page is a THP
 *   Bit 63:     page is present
 *
 * When swapped (bit 61 set):
 *   Bits 0-4:   swap type
 *   Bits 5-54:  swap offset
 */

#define PAGEMAP_ENTRY_SIZE 8
#define PAGE_SIZE 4096

struct page_info {
    int present;
    int swapped;
    int thp;
    int soft_dirty;
    uint64_t pfn;        /* Physical frame number */
    uint64_t swap_offset;
    int swap_type;
};

static int get_page_info(pid_t pid, unsigned long vaddr,
                          struct page_info *info)
{
    char path[64];
    int fd;
    uint64_t entry;
    off_t offset;

    memset(info, 0, sizeof(*info));

    snprintf(path, sizeof(path), "/proc/%d/pagemap", pid);
    fd = open(path, O_RDONLY);
    if (fd < 0) return -1;

    /* Calculate offset: (vaddr / PAGE_SIZE) * 8 */
    offset = (vaddr / PAGE_SIZE) * PAGEMAP_ENTRY_SIZE;
    if (pread(fd, &entry, sizeof(entry), offset) != sizeof(entry)) {
        close(fd);
        return -1;
    }
    close(fd);

    info->present = (entry >> 63) & 1;
    info->swapped = (entry >> 62) & 1;
    info->thp     = (entry >> 61) & 1;
    info->soft_dirty = (entry >> 55) & 1;

    if (info->present) {
        info->pfn = entry & 0x7FFFFFFFFFFFFFULL;
    } else if (info->swapped) {
        info->swap_type = entry & 0x1F;
        info->swap_offset = (entry >> 5) & 0x3FFFFFFFFFFFFULL;
    }

    return 0;
}

/*
 * Dump page mapping for a virtual address range.
 */
static void dump_mapping(pid_t pid, unsigned long start,
                          unsigned long end)
{
    struct page_info info;
    unsigned long addr;

    printf("%-16s %-8s %-12s %-6s %-6s %-6s\n",
           "Virt Addr", "Present", "PFN", "THP",
           "Swap", "Dirty");

    for (addr = start & ~(PAGE_SIZE-1); addr < end;
         addr += PAGE_SIZE) {
        if (get_page_info(pid, addr, &info) < 0)
            continue;

        printf("0x%012lx %-8s ",
               addr,
               info.present ? "yes" :
               (info.swapped ? "swap" : "no"));

        if (info.present)
            printf("%-12lu", info.pfn);
        else if (info.swapped)
            printf("%-12s", "N/A");
        else
            printf("%-12s", "-");

        printf(" %-6s %-6s %-6s\n",
               info.thp ? "yes" : "no",
               info.swapped ? "yes" : "no",
               info.soft_dirty ? "yes" : "no");
    }
}

int main(int argc, char *argv[])
{
    pid_t pid = argc > 1 ? atoi(argv[1]) : getpid();
    unsigned long start = 0x400000; /* example: code segment */
    unsigned long end = start + 16 * PAGE_SIZE;

    dump_mapping(pid, start, end);
    return 0;
}
```
pagemap is a powerful diagnostic tool but requires root (or CAP_SYS_ADMIN) because it reveals physical addresses, which can be used for row-hammer attacks. The soft-dirty bit (bit 55) is used by CRIU for incremental checkpoint — pages modified since the last clear_refs write have this bit set.

