使用timerfd+epoll的高精度定时器：

#include <sys/timerfd.h>
#include <sys/epoll.h>
#include <time.h>
#include <unistd.h>
#include <stdio.h>

int main()
{
    /* 创建单调时钟定时器 */
    int tfd = timerfd_create(CLOCK_MONOTONIC, TFD_CLOEXEC | TFD_NONBLOCK);

    /* 设置100ms间隔定时器 */
    struct itimerspec its = {
        .it_interval = { .tv_sec = 0, .tv_nsec = 100000000 }, /* 100ms */
        .it_value = { .tv_sec = 0, .tv_nsec = 100000000 }
    };
    timerfd_settime(tfd, 0, &its, NULL);

    int epfd = epoll_create1(0);
    struct epoll_event ev = { .events = EPOLLIN, .data.fd = tfd };
    epoll_ctl(epfd, EPOLL_CTL_ADD, tfd, &ev);

    int count = 0;
    struct epoll_event events[4];
    while (count < 10) {
        epoll_wait(epfd, events, 4, -1);
        uint64_t expirations;
        read(tfd, &expirations, sizeof(expirations));
        printf("Timer fired %lu times (total: %d)
",
               expirations, ++count);
    }

    close(tfd);
    close(epfd);
    return 0;
}

timerfd_create()创建基于hrtimer的文件描述符。CLOCK_MONOTONIC不受时间调整影响。read()返回自上次读取以来的到期次数（uint64_t），处理合并的到期事件。TFD_NONBLOCK使read不阻塞。

