```c
#include <linux/hrtimer.h>

struct my_dev {
    struct hrtimer timer;
    /* ... */
};

static enum hrtimer_restart my_hrtimer_cb(struct hrtimer *timer)
{
    struct my_dev *dev = container_of(timer, struct my_dev, timer);
    /* Process timer event */
    /* Return HRTIMER_RESTART to reschedule: */
    hrtimer_forward_now(timer, ms_to_ktime(10));
    return HRTIMER_RESTART;
    /* Or HRTIMER_NORESTART to stop */
}

/* Initialization */
hrtimer_init(&dev->timer, CLOCK_MONOTONIC, HRTIMER_MODE_REL);
dev->timer.function = my_hrtimer_cb;

/* Start with 100ms relative timeout */
hrtimer_start(&dev->timer, ms_to_ktime(100), HRTIMER_MODE_REL);

/* Or absolute timeout */
hrtimer_start(&dev->timer, ktime_set(1, 0), HRTIMER_MODE_ABS);

/* Cancel (synchronous - waits for running callback) */
hrtimer_cancel(&dev->timer);
```
The callback returns `HRTIMER_RESTART` (with `hrtimer_forward_now()` to set next expiry) or `HRTIMER_NORESTART`. Modes: `HRTIMER_MODE_REL` (relative to now), `HRTIMER_MODE_ABS` (absolute time), `HRTIMER_MODE_PINNED` (run on same CPU).

